module sr_latch (
    input S,
    input R,
    output reg obf_Q,
    output reg Qn
);
    always @(S, R) begin
        if (S && !R) begin
            obf_Q <= 1;
            Qn <= 0;
        end else if (!S && R) begin
            obf_Q <= 0;
            Qn <= 1;
        end else if (S && R) begin
            // Invalid state for SR Latch
            obf_Q <= 1'bx; // Indeterminate
            Qn <= 1'bx; // Indeterminate
        end
    end
endmodule
